[Fractional Bessel kernels --- implemented range]
	\label{rem:frac-bessel-implemented}
	{#1{
			For $\beta\le \frac32$, genuinely new arguments seem necessary already for the shell contribution in Section~\ref{sec:shell-vanishing-rewritten}, and also for the tail contribution in Section~\ref{sec:tail-vanishing-checked}. More precisely, the restriction $\beta>\frac32$ already appears in the weighted shell summability estimate in Section~\ref{sec:shell-vanishing-rewritten}, and reappears in Section~\ref{sec:tail-vanishing-checked} in both the weighted mixed-channel estimate and the control of the high--high off-diagonal block.
			For $\beta\le 1$ the present Schur estimate for the high--high block is no longer sufficient, while for $\beta\le \frac12$ the commutator summations from Sections~\ref{sec:high0}--\ref{sec:shell-vanishing-rewritten} already fail.}}

\label{lem:relent-signedA}
	Let $h>0$ be self-adjoint on the one-body space and let $A=A^\ast$ satisfy
	\begin{equation}
		\label{eq:A-upper-bound}
		A \le c\,h \qquad\text{for some }c\in(0,1).
	\end{equation}
	For $\lambda>0$ define the quasi-free Gibbs states
	\[
	\Gamma_s := Z_s^{-1}\exp\!\big(-\lambda\, \mathrm d\Gamma(h-sA)\big),\qquad s\in[0,1],
	\]
	with one-body density matrices
	\[
	\gamma_s := (e^{\lambda(h-sA)}-1)^{-1}.
	\]
	Then $\Gamma_s$ is well-defined for all $s\in[0,1]$ and the relative entropy satisfies
	\begin{equation}
		\label{eq:relent-bound}
		\mathcal{H}(\Gamma_1,\Gamma_0)
		\;\le\;
		C(c)\,\mathrm{Tr}\!\big(h^{-1}Ah^{-1}A\big).
	\end{equation}

\label{lem:exch2d}\label{lem:yukawa-lemma11-safe}
Then uniformly for \(|t|\le1\),
\begin{equation}\label{eq:yukawa-free-energy-upper}
	-\log\frac{\mathrm{Tr}(e^{-\mathbb{H}_\lambda^{\mathrm{re}}+tB})}{\mathrm{Tr}(e^{-\lambda \mathrm d\Gamma(h)+tB})}\le C.
\end{equation}
Consequently,
\begin{equation}\label{eq:yukawa-free-energy-functional}
	\mathcal{H}(\Gamma_{\lambda,t},\Gamma_{0,t})
	+\mathrm{Tr}\!\big(W^{\mathrm{re}}\Gamma_{\lambda,t}\big)
	\le C.
\end{equation}

[Weighted Hilbert--Schmidt estimate with logarithmic loss for the perturbed Gibbs states]
	\label{prop:one-body-HS-safe}
		Let $B$,
	$\Gamma_{\lambda,t}$ and $\Gamma_{0,t}$ be as in Lemma \ref{lem:yukawa-lemma11-safe}. Then there exists $C>0$ such that,
	for all sufficiently small $\lambda\in(0,1/2)$,
	\begin{equation}\label{eq:relative-entropy-log2}
		\sup_{|t|\le1}\mathcal{H}(\Gamma_{\lambda,t},\Gamma_{0,t})
		\le C(1+|\log\lambda|^2).
	\end{equation}
	Consequently,
	\begin{equation}\label{eq:one-body-HS-safe}
		\sup_{|t|\le1}
		\lambda\,
		\bigl\|
		\sqrt h\,(\Gamma_{\lambda,t}^{(1)}-\Gamma_{0,t}^{(1)})\,\sqrt h
		\bigr\|_{\mathrm{HS}}
		\le C(1+|\log\lambda|^2).
	\end{equation}
	In particular,
	\begin{equation}\label{eq:number-difference-global-safe}
		\sup_{|t|\le1}
		\lambda\,
		\left|
		\mathrm{Tr}\big[(\Gamma_{\lambda,t}^{(1)}-\Gamma_{0,t}^{(1)})\big]
		\right|
		\le
		C(1+|\log\lambda|^2).
	\end{equation}

[Second order correlation inequality] \label{thm:correlation-intro} Let $A$ be a self-adjoint operator on a separable Hilbert space such that $\mathrm{Tr} [e^{-sA} ] <+\infty$ holds for all $s> 0$. Let $B$ be a symmetric operator such that $B$ is $A$-relatively bounded with a relative bound strictly smaller than $1$. We also assume that the perturbed Gibbs states
	\begin{equation}\label{eq:Gibbs-t-intro}
		G_t = \frac{\exp(-A+tB)}{\mathrm{Tr} [ \exp(-A+tB) ]} , \quad t\in [-1,1]
	\end{equation}
	satisfy
	\begin{equation}\label{eq:CRI-condition-intro}
		\sup_{t\in [-1,1]}|\mathrm{Tr}(B G_t )| \le a.
	\end{equation}
	Then we have
	\begin{equation}\label{eq:StahlA2-intro}
		\mathrm{Tr}[ B^2 G_0 ] \leq a e^{a} + \frac{1}{4} \mathrm{Tr}[ [B, [A, B]] G_0].
	\end{equation}

[Blockwise Hilbert--Schmidt bounds]\label{lem:com1}
	Assume \(0<s_1<1\) and \(\frac12<s_2<1\). Then
	\begin{align}
		\pm (\mathcal C_{23}+\mathcal C_{56}+\mathcal C_{15})
		&\le
		C_{s_1,s_2}\lambda^2 \Lambda^{2-s_1-s_2}
		\mathbb{H}_{s_1}\mathbb{H}_{s_2},
		\label{eq:blockwise-HS-two-cutoff}
		\\
		\pm (\mathcal C_{36}+ \mathcal C_{78})
		&\le
		C_{s_1,s_2}\lambda^2 \Lambda^{1-s_1}
		\mathbb{H}_{s_1}\mathbb{H}_{s_2},
		\label{eq:blockwise-HS-36}
%		\\
%		\pm \mathcal C_{78}
%		&\le
%		C_{s_1,s_2}\lambda^2 \Lambda^{1-s_1}
%		(\mathbb{H}_{s_1}+1)(\mathbb{H}_{s_2}+1).
%		\label{eq:blockwise-HS-78}
	\end{align}
	In particular, as a quadratic form on \(\mathfrak F_{\mathrm{fin}}\),
	\[
	\pm [\mathcal N_Q,[W^{\mathrm{re}}_{\neq0},\mathcal N_Q]]
	\le
	C_{s_1,s_2}\lambda^2
	\Lambda^{2-s_1-s_2}
	\mathbb{H}_{s_1}\mathbb{H}_{s_2}.
	\]

[Vanishing of the shell contribution]
	\label{prop:shell-vanishing-local}
	{#1{Fix $\frac32<\beta\le2$ and choose $\eta\in(2-\beta,\beta-1)$ and \(\frac34-\alpha_1-\frac\alpha2(2-\beta)>0\). Then}}
	\begin{equation}
		\label{eq:shell-vanishing-rate-local}
		|\mathcal E_{\rm shell}(\Gamma_\lambda)|
		\le
		{#1{C_\beta(1+|\log\lambda|)^{5/2}\Lambda^{(2-\beta)/2}\bigl(\Lambda^{-\eta/2}+\lambda^{3/4}\Lambda_1\bigr)
		+
		C_\beta\lambda (1+|\log\lambda|^2)\Lambda_1^{2-\beta}\longrightarrow0.}}
	\end{equation}

[Quadratic decomposition of the shell part]
	\label{lem:shell-decomposition-local}
	There exists a one-body remainder $R_{\rm shell}^{(1)}(\Gamma)$ such that
	\begin{equation}
		\label{eq:shell-decomposition-local}
		\mathcal E_{\rm shell}(\Gamma)
		=
		\frac{\lambda^2}{4}
		\sum_{\ell\neq 0}#1{\widehat v_\beta}(\ell)\,
		\mathrm{Tr}\Big[\Big(
		A_\ell B_{-\ell}+B_\ell A_{-\ell}+B_\ell B_{-\ell}
		\Big)\Gamma\Big]
		+
		R_{\rm shell}^{(1)}(\Gamma),
	\end{equation}
	where $A_\ell$ and $B_\ell$ are defined in \eqref{eq:def-shell-A-B}.  Moreover,
	\begin{equation}
		\label{eq:shell-remainder-local}
		{\color{red}|R_{\rm shell}^{(1)}(\Gamma_\lambda)|
		\le
		C_\beta\lambda L_\lambda(1+\log\Lambda_1)\Lambda_1^{2-\beta}.}
	\end{equation}

[Hilbert--Schmidt bounds for the shell observables]
	\label{lem:shell-HS-local}
	Fix $\eta\in(0,1)$. Then for every $(A,B)\in\mathcal C_{\rm shell}$ and every
	$\ell\in\mathbb Z^2$,
	\begin{equation}
		\label{eq:shell-HS-local}
		\bigl\|
		h^{-1/2}f_{\ell,\pm}^{A,B}h^{-1/2}
		\bigr\|_{\mathrm{HS}}
		\le
		C_\eta\,
		\langle\ell\rangle^{-1+\eta+\kappa}\Lambda^{-\eta}\,\mathbf 1_{\{|\ell|\lesssim \Lambda_1\}},
	\end{equation}
	for $\kappa>0$.

[Double commutators with $h$]
	\label{lem:shell-h-comm-local}
	For every $(A,B)\in\mathcal C_{\rm shell}$ and every $\ell\neq0$,
	\begin{equation}
		\label{eq:shell-h-comm-local}
		\bigl\|
		[f_{\ell,\pm}^{A,B},[f_{\ell,\pm}^{A,B},h]]
		\bigr\|
		\le
		C\Lambda_1^2\,\mathbf 1_{\{|\ell|\lesssim \Lambda_1\}}.
	\end{equation}

[Double commutator with $W_{\neq0}^{\rm re}$ for the shell modes]
	\label{lem:shell-W-comm-local}
	Fix
	\(
	0<s_1\le s_2<1,
	s_2>\frac12,
	s_1+s_2<1.
	\)
	Then for every $(A,B)\in\mathcal C_{\rm shell}$ and every $\ell\neq0$,
	\begin{equation}
		\label{eq:shell-W-comm-local}
		\pm
		[\mathrm d\Gamma(f_{\ell,\pm}^{A,B}),
		[\mathrm d\Gamma(f_{\ell,\pm}^{A,B}),W_{\neq0}^{\rm re}]]
		\le
		C\lambda^2\Lambda_1^{2-s_1-s_2}\langle\ell\rangle^{-s_1}
		\mathbb{H}_{s_1}\mathbb{H}_{s_2}\,\mathbf 1_{\{|\ell|\lesssim \Lambda_1\}}
	\end{equation}
	as quadratic forms on $\mathfrak F_{\rm fin}$.

[Mode-by-mode shell bound]
	\label{prop:shell-mode-local}

	It holds that for every $(A,B)\in\mathcal C_{\rm shell}$, every $\ell\neq0$, and every
	{\color{red}$0<s_1\le s_2<1$ with $s_2>\frac12$ and $s_1+s_2<1$,}
	\begin{equation}
		\label{eq:shell-mode-local}
		\lambda^2
		\mathrm{Tr}\!\Big(
		(\rho_\ell^{A,B})^*\rho_\ell^{A,B}\Gamma_\lambda
		\Big)
		\le
		C\mathbf 1_{\{|\ell|\lesssim \Lambda_1\}}\Big(
		\langle\ell\rangle^{-1+\eta+\kappa}\Lambda^{-\eta}L_\lambda^2
		+
		\lambda^2\Lambda_1^2L_\lambda^2
		+
		{\color{red}\lambda^{2-s_1-s_2}\Lambda_1^{2-s_1-s_2}\langle\ell\rangle^{-s_1}L_\lambda^2}
		\Big).
	\end{equation}
{\color{red}Here $\eta\in(2-\beta,\beta-1-\kappa)$ is fixed and $\kappa>0$.}

[Tail contribution in the lower bound]
	\label{cor:tail-lower-bound}
	{#1{The tail remainder satisfies}}
	\begin{equation}
		\label{eq:tail-lower-rate}
		\mathcal E_{\rm tail}(\Gamma_\lambda)\ge -{#1{C_\beta\,\mathfrak r^{\rm tail}_{\beta,\lambda}}}.
	\end{equation}

[Quantitative bound on the explicit $R_1$-correction]
	\label{lem:Q1-tail-quantitative}
	\label{lem:R1-correction}
	It holds that,
	\[
	\lambda^2\mathrm{Tr}_{H^{\otimes_s2}}\!\big(Q_1^{\otimes2}\Gamma_\lambda^{(2)}\big)
	\le \lambda^2\mathrm{Tr}_{\mathfrak F(H)}(\mathcal N_{Q_1}^2\Gamma_\lambda) \leq
	C
	\lambda^{3/2-2\alpha_1}(1+|\log\lambda|^2),
	\]
	\begin{equation}
		\label{eq:R1-correction-rate-special}
		\frac{\lambda^2}{2(2\pi)^2}
		\mathrm{Tr}_{H^{\otimes_s2}}(R_1\Gamma_\lambda^{(2)})
		\le
		C
		\lambda^{3/4-\alpha_1}(1+|\log\lambda|^2).
	\end{equation}

[Exact decomposition of the mixed off-diagonal part]
	\label{lem:exact-mixed-decomp}
	For the full Bessel operator
	\[
	V=\sum_{k\in\mathbb Z^2}\rmk{\widehat v_\beta}(k)(e_k\otimes e_{-k}),
	\]
	one has
	\begin{equation}
		\frac{\lambda^2}{2}\mathbb W(\Pi_1VR_1+R_1V\Pi_1)
		=
		\frac{\lambda^2}{4}
		\sum_{k\in\mathbb Z^2}#1{\widehat v_\beta}(k)
		\Big(A_kB_{-k}+A_{-k}B_k+B_kB_{-k}+C_kA_{-k}+C_{-k}A_k+C_kC_{-k}\Big).
		\label{eq:exact-mixed-decomp}
	\end{equation}
 Since $SQ_1=Q_1S=0$, no one-body correction term appears.

[Control of the shell--mixed cross terms]
	\label{lem:cross-terms-controlled}
	{#1{It holds that}}
	\begin{align}
		&\sum_{k\in\mathbb Z^2}#1{\widehat v_\beta}(k)\lambda^2
		\Big|\mathrm{Tr}(A_kB_{-k}\Gamma_\lambda)\Big|
		+
		\sum_{k\in\mathbb Z^2}#1{\widehat v_\beta}(k)\lambda^2
		\Big|\mathrm{Tr}(A_{-k}B_k\Gamma_\lambda)\Big|
		\notag
		\\
		&\qquad+
		\sum_{k\in\mathbb Z^2}#1{\widehat v_\beta}(k)\lambda^2
		\Big|\mathrm{Tr}(C_kA_{-k}\Gamma_\lambda)\Big|
		+
		\sum_{k\in\mathbb Z^2}#1{\widehat v_\beta}(k)\lambda^2
		\Big|\mathrm{Tr}(C_{-k}A_k\Gamma_\lambda)\Big|\notag
		\\ &\leq {#1{C_\beta\,\mathfrak r^{\rm tail}_{\beta,\lambda}.}}
		\label{eq:cross-terms-vanish}
	\end{align}

[Weighted mixed-channel estimate]
	\label{prop:weighted-mixed}
	Let $L\in\{P,P_1,S\}$ and define
	\[
	\rho_\ell^{L,Q_1}:=\mathrm d\Gamma(Le_\ell Q_1),
	\qquad \ell\in\mathbb Z^2.
	\]
	Then
	\begin{equation}
		\sum_{\ell\in\mathbb Z^2}#1{\widehat v_\beta}(\ell)\,
		\lambda^2\mathrm{Tr}_{\mathfrak F}
		\Bigl((\rho_\ell^{L,Q_1})^*\rho_\ell^{L,Q_1}\Gamma_\lambda\Bigr)\leq {#1{C_\beta (1+|\log \lambda|^3)\lambda^{3/4-\alpha_1(3-\beta)}}} .
		\label{eq:weighted-mixed-vanishes}
	\end{equation}

[The high--high mixed pair as a two-body off-diagonal block]
	\label{lem:Thh-two-body}
	Define the two-body operator
	\[
	\mathbb T_{\rm hh}
	:=
	\sum_{k\in\mathbb Z^2}\rmk{\widehat v_\beta}(k)
	\bigl(Se_kQ_1\otimes Se_{-k}Q_1\bigr)
	\]
	on $H^{\otimes 2}$. Then
	\[
	\mathbb T_{\rm hh}=(S\otimes S)\mathbb T_{\rm hh}(Q_1\otimes Q_1),
	\qquad
	\mathbb T_{\rm hh}^*=(Q_1\otimes Q_1)\mathbb T_{\rm hh}^*(S\otimes S).
	\]
	Moreover,
	\begin{equation}
		\mathcal T_{\rm hh}
		=
		\frac{\lambda^2}{2}\mathrm{Tr}_{H^{\otimes 2}}
		\Bigl((\mathbb T_{\rm hh}+\mathbb T_{\rm hh}^*)\Gamma_\lambda^{(2)}\Bigr).
		\label{eq:Thh-two-body}
	\end{equation}

[Operator norm bound for the high--high block]
	\label{lem:Thh-norm}
	With $\mathbb T_{\rm hh}$ as in Lemma~\ref{lem:Thh-two-body}, one has
	\begin{equation}
		\|\mathbb T_{\rm hh}\|_{\mathrm{op}}\le {#1{C_\beta(1+\log \Lambda_1)\Lambda_1^{2-\beta}}}.
		\label{eq:Thh-norm}
	\end{equation}

[Block Cauchy--Schwarz for positive trace-class operators]
	\label{lem:block-cs}
	Let $\Gamma\ge 0$ be trace-class on a Hilbert space $\mathfrak H$, let $\Pi_1,\Pi_2$ be orthogonal projections, and let $T=\Pi_1T\Pi_2$ be bounded. Then
	\[
	\big|\mathrm{Tr}_{\mathfrak H}(T\Gamma)\big|
	\le \|T\|_{\mathrm{op}}
	\Big(\mathrm{Tr}_{\mathfrak H}(\Pi_1\Gamma)\Big)^{1/2}
	\Big(\mathrm{Tr}_{\mathfrak H}(\Pi_2\Gamma)\Big)^{1/2}.
	\]

[Proof of Theorem \ref{cor:tail-lower-bound}]
	By Lemma~\ref{lem:exact-mixed-decomp}, Lemma~\ref{lem:cross-terms-controlled}, and Proposition~\ref{prop:high-high-mixed-vanishes}, we obtain
	\[
	\frac{\lambda^2}{2}
	\mathrm{Tr}_{H^{\otimes 2}}
	\Bigl((\Pi_1VR_1+R_1V\Pi_1)\Gamma_\lambda^{(2)}\Bigr)
	\ge -{C_\beta\,\mathfrak r^{\rm tail}_{\beta,\lambda}.}
	\]
	Combining this with \eqref{eq:R1-correction-rate-special} yields \eqref{eq:tail-lower-rate}.

[Quantitative quantum de Finetti]\label{thm:quant deF}
		For all $k\in\mathbb N$, we have
		\begin{equation}\label{Peq:Chiribella}
			\int_{P\mathfrak{H}}|u^{\otimes k}\rangle\langle u^{\otimes k}|\,\,\mathrm d^\lambda_{P,\Gamma}(u)
			=
			k!\lambda^k\Gamma_P^{(k)}
			+
			k!\lambda^k\sum_{\ell=0}^{k-1}\binom{k}{\ell}\,
			\Gamma_P^{(\ell)}\otimes_s \mathbf 1_{(P\mathfrak{H})^{\otimes_s (k-\ell)}}.
		\end{equation}
		Thus, with $d=\mathrm{Tr}[P]$,
		\begin{equation}\label{eq:quantitative}
			\mathrm{Tr}\left| k!\lambda^k\Gamma_P^{(k)}-\int_{P\mathfrak{H}}|u^{\otimes k}\rangle\langle u^{\otimes k}|\,\,\mathrm d^\lambda_{P,\Gamma}(u) \right|
			\le \lambda^k \sum_{\ell=0}^{k-1}\binom{k}{\ell}^2 \frac{(k-\ell+d-1)!}{(d-1)!}\mathrm{Tr}\left[ \mathcal N^{\ell}\Gamma_P\right].
		\end{equation}

[Explicit $k\neq0$ de Finetti expansion against $V_{\neq0,P}$]
	\label{lem:nonzero-explicit-corrected}
	Let $\mu^{\lambda}_{P,\Gamma}$ be the lower symbol on $PH$ at scale $\lambda$. Then
	\begin{equation}
		\Big|\lambda^2\,\mathrm{Tr}_{\mathfrak F(PH)}\bigl(\mathbb W(V_{\neq 0,P})\Gamma_P\bigr)
		-
		\frac1{2}\sum_{k\neq 0}#1{\widehat v_\beta}(k)
		\int_{PH}|\langle u,e_{k,P}u\rangle|^2\,\,\mathrm d^{\lambda}_{P,\Gamma}(u)\Big|\le {#1{C_\beta\lambda^2\Lambda^{4-\beta}(1+\log\Lambda)}}
		.
		\label{eq:213}
	\end{equation}

[Finite-dimensional interaction comparison]
	\label{prop:localized-interaction-vs-DP}
	For every state $\Gamma$ on $\mathfrak F(H)$,
	\begin{equation}\label{eq:localized-interaction-vs-DP}
		\mathrm{Tr}_{\mathfrak F(PH)}\!\big[W_P^{\mathrm{re}}\Gamma_P\big]
		=
		\int_{PH} D_P(u)\,\,\mathrm d^\lambda_{P,\Gamma}(u)
		+
		\mathcal E_{P,\lambda}(\Gamma),
	\end{equation}
	where
	\begin{align}
		|\mathcal E_{P,\lambda}(\Gamma)|
		&\le
		{#1{C_\beta\lambda^2 \Lambda^{4-\beta}(1+\log\Lambda)}}
		+
		C\lambda \Lambda^2
		\left(
		\log\Lambda+\int_{PH}\|u\|^2\,\,\mathrm d^\lambda_{P,\Gamma}(u)
		\right).
		\label{eq:localized-interaction-vs-DP-error}
	\end{align}

[Second moment of the Husimi field]
	\label{cor:husimi-second-moment}
	Let
	\(
	\mu^\lambda_{P,\lambda}:=\mu^\lambda_{P,\Gamma_\lambda}
	\)
	be the lower symbol of the localized interacting Gibbs state. Then
	\begin{equation}\label{eq:husimi-second-moment-log}
		\int_{PH}\|u\|^2\,\,\mathrm d^\lambda_{P,\lambda}(u)
		\le C(1+|\log\lambda|).
	\end{equation}

[Free-energy lower bound modulo high-frequency remainders]
	\label{prop:free-energy-lower-modulo-HF}
	Let $\Gamma_\lambda$ be the interacting Gibbs state. Then
	\begin{align}
		-\log \frac{Z_\lambda^{\mathrm{re}}}{Z_0}
	\ge
		\mathcal{H}_{\mathrm{cl}}(\mu^\lambda_{P,\lambda},\mu_{0,P})
		+
		\int_{PH} D_P(u)\,\,\mathrm d^\lambda_{P,\lambda}(u)
		+
		HF_{\neq0}(\Gamma_\lambda)
		+
		HF_0(\Gamma_\lambda)
		-
		R_{\lambda,\Lambda},
		\label{eq:free-energy-lower-modulo-HF}
	\end{align}
	where $\mu^\lambda_{P,\lambda}:=\mu^\lambda_{P,\Gamma_\lambda}$ and
	\begin{align}
		R_{\lambda,\Lambda}
		&\le
	C\lambda \Lambda^4|\log\lambda|.
		\label{eq:R-lambda-Lambda}
	\end{align}
%
