[Free-energy lower bound by the classical partition function]
	\label{thm:lower-bound-classical-final}
{#1{Fix $\frac32<\beta\le2$, choose $\eta\in(2-\beta,\beta-1)$, then choose $\alpha\in(0,1/4)$ sufficiently small and $\alpha_1>\frac12$ sufficiently close to $\frac12$ so that $\mathfrak r^{\rm tail}_{\beta,\lambda}\to0$. Under this choice one has}}
	\begin{equation}\label{eq:lower-bound-classical-final}
		-\log \frac{Z_\lambda^{\mathrm{re}}}{Z_0}
		\ge
		-\log \int_{PH} e^{-D_P(u)}\,\,\mathrm d_{0,P}(u)
		-{#1{C_\beta\Big(\mathfrak r^{\rm tail}_{\beta,\lambda}+(\lambda^{\frac\alpha4}+\lambda^{\frac{\alpha(\eta-2+\beta)}{2}})(1+|\log\lambda|^3)\Big).}}
	\end{equation}

[Vanishing of the high-frequency remainders for the trial state]
	\label{lem:upper}
It holds that
		\begin{equation}
			\label{eq:trial-HF-explicit}
			|HF_{\neq0}(\widetilde\Gamma_\lambda)|+|HF_0(\widetilde\Gamma_\lambda)|
			\le
			{\color{red}C_\beta(1+|\log\lambda|)^2\Lambda^{-\beta}.}
		\end{equation}

[Free-energy upper bound via the trial state $\widetilde\Gamma_\lambda$]
	\label{prop:free-energy-upper-final}	{\color{red}Fix $\frac32<\beta\le2$.} It holds that
	\begin{equation}\label{eq:upper-bound-classical-final}
		-\log\frac{Z^{\rm re}_\lambda}{Z_0}
		\le
		-\log \int_{PH} e^{-D_P(u)}\,\,\mathrm d_{0,P}(u)+{\color{red}C_\beta(1+|\log\lambda|)^2(\lambda^{\alpha\beta}+\lambda^{1-4\alpha})}
		.
	\end{equation}

\label{lem:class}It holds that
	\begin{equation}
		\label{eq:HS-DP-to-D-L1}
		D_P(P\cdot)\longrightarrow D
		\qquad\text{in }L^1(\mu_0).
	\end{equation}
	and the following hold for every fixed $k\ge1$.
	One has
	\begin{equation}
		\label{eq:HS-DP-D-positive}
		D_P(u)\ge0\quad\text{for all }u\in PH,
		\qquad
		D(u)\ge0\quad\text{for }\mu_0\text{-a.e. }u.
	\end{equation}
	Consequently,
	\begin{equation}
		\label{eq:HS-gP-to-g-L1}
		g_P:=z_P^{-1}e^{-D_P(P\cdot)}
		\longrightarrow
		g:=z_{\rm cl}^{-1}e^{-D}
		\qquad\text{in }L^1(\mu_0),
	\end{equation}
	and
	\begin{equation}
		\label{eq:HS-nu-dominated-by-mu0}
		\,\mathrm d(u)=g(u)\,\,\mathrm d_0(u)\le z_{\rm cl}^{-1}\,\,\mathrm d_0(u).
	\end{equation}

[Convergence of the relative free energy]
	\label{thm:free-energy-convergence-final}
	It holds that
	\begin{equation}\label{eq:free-energy-convergence-final}
		-\log \frac{Z_\lambda^{\mathrm{re}}}{Z_0}
		\longrightarrow
		-\log z_{\mathrm{cl}}
		\qquad (\lambda\downarrow0),
	\end{equation}
	where
	\[
	z_{\mathrm{cl}}:=\int e^{-D(u)}\,\,\mathrm d\mu_0(u)
	\]
	{\color{red}is the partition function of the limiting fractional-Bessel Gibbs measure.}

[Weighted convergence of the lower symbol]
	\label{prop:weighted-lower-symbol}
For the parameter as in Section \ref{sec:free-energy-density}	it holds that
	\begin{equation}
		\label{eq:l1-verified-weighted}
		\|\mu^\lambda_{P,\lambda}-\nu_P\|_{L^1(PH)}^2 \le
		{\color{red}C_\beta\Bigl((1+|\log\lambda|)^3(\lambda^{\frac\alpha4}+\lambda^{\frac{\alpha(\eta-2+\beta)}{2}})+\mathfrak r^{\rm tail}_{\beta,\lambda}\Bigr).}
	\end{equation}
	Consequently, for every $\phi\in L^2(\mathbb T^2)$ with finitely supported Fourier transform and every
	$n\ge1$,
	\begin{equation}
		\label{eq:weighted-l1-lower-symbol}
		\int_{PH} |\langle \phi,u\rangle|^{2n}
		\,|\,\mathrm d^\lambda_{P,\lambda}-\,\mathrm d_P|(u)
		\le
		{\color{red}C_{\phi,n}\,(1+|\log\lambda|)^n\Bigl((1+|\log\lambda|)^3(\lambda^{\frac\alpha4}+\lambda^{\frac{\alpha(\eta-2+\beta)}{2}})+\mathfrak r^{\rm tail}_{\beta,\lambda}\Bigr)^{1/4}.}
	\end{equation}
	In particular, the left side of \eqref{eq:weighted-l1-lower-symbol} tends to $0$.

\label{prop:HS-classical-cutoff-limit}
	For every fixed $k \ge 1$, the following hold.

	\begin{enumerate}
		\item The $k$-point correlation operator
		\begin{equation}
			\gamma^{(k)}_\nu := \int |u^{\otimes k}\rangle \langle u^{\otimes k}|\, d\nu(u)
		\end{equation}
		extends uniquely to a positive operator in $\mathfrak S^2(H^{\otimes_s k})$ and satisfies
		\begin{equation}
			0 \le \gamma^{(k)}_\nu \le z_{\mathrm{cl}}^{-1}\gamma^{(k)}_{\mu_0}
			= z_{\mathrm{cl}}^{-1} k! (h^{-1})^{\otimes_s k}.
		\end{equation}
		Similarly,
		\begin{equation}
			0 \le \gamma^{(k)}_{\nu_P} \le c_0^{-1} k! (h^{-1})^{\otimes_s k},
			\qquad c_0 := \inf_{\lambda \ll 1} z_P > 0.
		\end{equation}

		\item The classical cutoffs converge in Hilbert--Schmidt norm:
		\begin{equation}
			\|\gamma^{(k)}_{\nu_P} - \gamma^{(k)}_\nu\|_{\mathfrak S^2(H^{\otimes_s k})} \longrightarrow 0
			\qquad (\lambda \downarrow 0).
		\end{equation}
	\end{enumerate}

\label{prop:HS-trial-vs-true-state}
	With $\varepsilon_\lambda$ defined in \eqref{eq:HS-main-epsilon-lambda}, one has
	\begin{equation}
		\label{eq:HS-trial-vs-true-relative-entropy}
		\mathcal H(\widetilde\Gamma_\lambda,\Gamma_\lambda)
		\le C\varepsilon_\lambda,
	\end{equation}
	and consequently
	\begin{equation}
		\label{eq:HS-trial-vs-true-trace}
		\|\widetilde\Gamma_\lambda-\Gamma_\lambda\|_{\mathfrak S^1}
		\le C\varepsilon_\lambda^{1/2}.
	\end{equation}
	In particular,
	\begin{equation}
		\label{eq:HS-low-localized-trace}
		\|\Gamma_{P,\lambda}^{\rm re}-\Gamma_{\lambda,P}\|_{\mathfrak S^1}
		\le C\varepsilon_\lambda^{1/2}.
	\end{equation}

\label{cor:HS-true-vs-hat-state}
	One has
	\begin{equation}
		\label{eq:HS-true-vs-hat-trace}
		\|\Gamma_\lambda-\widehat\Gamma_\lambda\|_{\mathfrak S^1}
		\le C\varepsilon_\lambda^{1/2}.
	\end{equation}
	Moreover,
	\begin{equation}
		\label{eq:HS-high-localized-trace}
		\|(\Gamma_\lambda)_Q-\Gamma_{0,Q}\|_{\mathfrak S^1}
		\le C\varepsilon_\lambda^{1/2}
	\end{equation}
	and
	\begin{equation}
		\label{eq:HS-nearly-product-state}
		\Bigl\|
		\Gamma_\lambda-U^*\bigl(\Gamma_{\lambda,P}\otimes(\Gamma_\lambda)_Q\bigr)U
		\Bigr\|_{\mathfrak S^1}
		\le C\varepsilon_\lambda^{1/2}.
	\end{equation}

[A trace-class estimate for reduced density matrices]
	\label{lem:HS-states-to-rdm-trace}
	Let $q,q'>1$ be conjugate exponents, and let $\Gamma,\Gamma'$ be two states on bosonic Fock space commuting with the number operator. Then for every $k\ge1$,
	\begin{equation}
		\label{eq:HS-states-to-rdm-trace}
		\|\Gamma^{(k)}-\Gamma'^{(k)}\|_{\mathfrak S^1}
		\le
		\|\Gamma-\Gamma'\|_{\mathfrak S^1}^{1/q'}
		\Bigl(\mathrm{Tr}[\mathcal N^{qk}(\Gamma+\Gamma')]\Bigr)^{1/q}.
	\end{equation}

\label{prop:HS-state-to-rdm-scaled}
	For every fixed $k\ge1$,
	\begin{equation}
		\label{eq:HS-state-to-rdm-scaled-trace}
		\|\lambda^k(\Gamma_\lambda^{(k)}-\widehat\Gamma_\lambda^{(k)})\|_{\mathfrak S^1}
		\le
		C_k(1+|\log\lambda|)^k\varepsilon_\lambda^{1/4}.
	\end{equation}
	Consequently,
	\begin{equation}
		\label{eq:HS-state-to-rdm-scaled-HS}
		\|\lambda^k(\Gamma_\lambda^{(k)}-\widehat\Gamma_\lambda^{(k)})\|_{\mathfrak S^2}
		\le
		C_k(1+|\log\lambda|)^k\varepsilon_\lambda^{1/4}.
	\end{equation}
	In particular, since
	\begin{equation}
		\label{eq:HS-r-k-def}
		r_{\lambda,k}:=(1+|\log\lambda|)^k\varepsilon_\lambda^{1/4}\to0.
	\end{equation}

entries.proof:
Apply Lemma~\ref{lem:HS-states-to-rdm-trace} with $q=q'=2$, $\Gamma=\Gamma_\lambda$, and $\Gamma'=\widehat\Gamma_\lambda$. This gives
	\begin{equation}
		\label{eq:HS-state-to-rdm-proof-step}
		\|\lambda^k(\Gamma_\lambda^{(k)}-\widehat\Gamma_\lambda^{(k)})\|_{\mathfrak S^1}
		\le
		\|\Gamma_\lambda-\widehat\Gamma_\lambda\|_{\mathfrak S^1}^{1/2}
		\Bigl(
		\lambda^{2k}\mathrm{Tr}[\mathcal N^{2k}(\Gamma_\lambda+\widehat\Gamma_\lambda)]
		\Bigr)^{1/2}.
	\end{equation}
	By Corollary~\ref{cor:HS-true-vs-hat-state},
	\[
	\|\Gamma_\lambda-\widehat\Gamma_\lambda\|_{\mathfrak S^1}^{1/2}
	\le C\varepsilon_\lambda^{1/4}.
	\]
	For the second factor, Proposition~\ref{prop:number-moments-log} with $t=0$ yields
	\[
	\lambda^{2k}\mathrm{Tr}(\mathcal N^{2k}\Gamma_\lambda)
	\le C_k(1+|\log\lambda|)^{2k}.
	\]
	Moreover,
	\[
	U\widehat\Gamma_\lambda U^*=\Gamma_{\lambda,P}\otimes\Gamma_{0,Q},
	\qquad
	\mathcal N=\mathcal N_P+\mathcal N_Q,
	\qquad
	\mathcal N^{2k}\le 2^{2k-1}(\mathcal N_P^{2k}+\mathcal N_Q^{2k}).
	\]
	Hence
	\begin{align*}
		{\color{red}\lambda^{2k}\mathrm{Tr}(\mathcal N^{2k}\widehat\Gamma_\lambda)}
		&\le
		{\color{red}C_k\bigl(\lambda^{2k}\mathrm{Tr}(\mathcal N_P^{2k}\Gamma_{\lambda,P})+\lambda^{2k}\mathrm{Tr}(\mathcal N_Q^{2k}\Gamma_{0,Q})\bigr)}
		\\
		&\le
		{\color{red}C_k\bigl(\lambda^{2k}\mathrm{Tr}(\mathcal N^{2k}\Gamma_\lambda)+\lambda^{2k}\mathrm{Tr}(\mathcal N^{2k}\Gamma_0)\bigr)}
		\\
		&\le {\color{red}C_k(1+|\log\lambda|)^{2k},}
	\end{align*}
{\color{red}by Proposition~\ref{prop:number-moments-log}.}
	Inserting these bounds into \eqref{eq:HS-state-to-rdm-proof-step} proves \eqref{eq:HS-state-to-rdm-scaled-trace}. The Hilbert--Schmidt bound \eqref{eq:HS-state-to-rdm-scaled-HS} follows from
	\(
	\|A\|_{\mathfrak S^2}\le \|A\|_{\mathfrak S^1}
	\).

