\label{lem:HS-tensor-product-rdm-expansion}
	Let $\Gamma_P$ be a state on $\mathfrak{F}(PH)$ and $\Gamma_Q$ a state on $\mathfrak{F}(QH)$. Define
	\[
	\Gamma:=U^*(\Gamma_P\otimes\Gamma_Q)U.
	\]
	Then for every $k\ge1$,
	\begin{equation}
		\label{eq:HS-tensor-product-rdm-expansion}
		\Gamma^{(k)}
		=
		\sum_{\ell=0}^k
		\binom{k}{\ell}
		\Gamma_P^{(\ell)}\otimes_s \Gamma_Q^{(k-\ell)}.
	\end{equation}

[Reduction to the low-frequency block, with rate]
	\label{prop:HS-hat-to-low-frequency}
	For every fixed $k\ge1$,
	\begin{equation}
		\label{eq:HS-hat-to-low-frequency}
		\|k!\lambda^k\widehat\Gamma_\lambda^{(k)}-k!\lambda^k\Gamma_{\lambda,P}^{(k)}\|_{\mathfrak S^2}
		\le C_k\lambda^\alpha(1+|\log\lambda|)^k.
	\end{equation}
	Consequently,
	\begin{equation}
		\label{eq:HS-true-to-low-frequency}
		\|k!\lambda^k\Gamma_\lambda^{(k)}-k!\lambda^k\Gamma_{\lambda,P}^{(k)}\|_{\mathfrak S^2}
		\le C_k\Bigl(r_{\lambda,k}+\lambda^\alpha(1+|\log\lambda|)^k\Bigr).
	\end{equation}

\label{prop:HS-deFinetti-remainder-vanish}
	For every fixed $k\ge1$,
	\begin{equation}
		\label{eq:HS-deFinetti-remainder-trace}
		\|k!\lambda^k\Gamma_{\lambda,P}^{(k)}-M_{\lambda,P}^{(k)}\|_{\mathfrak S^1}
		\le
		C_k\sum_{\ell=0}^{k-1}(\lambda K)^{k-\ell}(1+|\log\lambda|)^\ell.
	\end{equation}
	Hence also
	\begin{equation}
		\label{eq:HS-deFinetti-remainder-HS}
		\|k!\lambda^k\Gamma_{\lambda,P}^{(k)}-M_{\lambda,P}^{(k)}\|_{\mathfrak S^2}
		\le
		C_k\sum_{\ell=0}^{k-1}(\lambda K)^{k-\ell}(1+|\log\lambda|)^\ell.
	\end{equation}
	In particular, the right-hand side tends to $0$.

\label{lem:HS-full-norm-moment-mu}
	For every fixed integer $m\ge1$,
	\begin{equation}
		\label{eq:HS-full-norm-moment-mu}
		\int_{PH}\|u\|^{2m}\,\,\mathrm d^\lambda_{P,\lambda}(u)
		\le
		C_m(1+|\log\lambda|)^m.
	\end{equation}

\label{lem:HS-full-norm-moment-nuP}
	For every fixed integer $m\ge1$,
	\begin{equation}
		\label{eq:HS-full-norm-moment-nuP}
		\int_{PH}\|u\|^{2m}\,\,\mathrm d_P(u)
		\le
		C_m(1+|\log\lambda|)^m.
	\end{equation}

\label{lem:HS-L1-to-moment-operator}
	Let $\mu$ and $\eta$ be two probability measures on a finite-dimensional complex Hilbert space $E$. For every $k\ge1$, define
	\[
	M_\mu^{(k)}:=\int_E |u^{\otimes k}\rangle\langle u^{\otimes k}|\,\,\mathrm d\mu(u),
	\qquad
	M_\eta^{(k)}:=\int_E |u^{\otimes k}\rangle\langle u^{\otimes k}|\,\,\mathrm d\eta(u).
	\]
	Then
	\begin{equation}
		\label{eq:HS-L1-to-moment-operator}
		\|M_\mu^{(k)}-M_\eta^{(k)}\|_{\mathfrak S^2}
		\le
		\Bigl(
		\int_E\|u\|^{4k}\,\,\mathrm d(u)+\int_E\|u\|^{4k}\,\,\mathrm d(u)
		\Bigr)^{1/2}
		\|\mu-\eta\|_{L^1(E)}^{1/2}.
	\end{equation}

\label{prop:HS-low-frequency-to-fd-classical}
	For every fixed $k\ge1$,
	\begin{equation}
		\label{eq:HS-M-lambdaP-to-gamma-nuP}
		\|M_{\lambda,P}^{(k)}-\gamma_{\nu_P}^{(k)}\|_{\mathfrak S^2}
		\le C_k r_{\lambda,k}.
	\end{equation}
	Consequently,
	\begin{equation}
		\label{eq:HS-low-frequency-to-fd-classical-main}
		\|k!\lambda^k\Gamma_{\lambda,P}^{(k)}-\gamma_{\nu_P}^{(k)}\|_{\mathfrak S^2}
		\le C_k\Bigl(r_{\lambda,k}+\sum_{\ell=0}^{k-1}(\lambda K)^{k-\ell}(1+|\log\lambda|)^\ell\Bigr).
	\end{equation}

[Positive lower bound away from the diagonal]
	\label{lem:periodic-yukawa-positive}
	{#1{Let}}
	\[
	{\rmk{v_\beta}=(1-\Delta)^{-\beta/2}}
	\qquad\text{on }\mathbb T^2=[0,2\pi]^2,
	\qquad {\frac32<\beta\le2.}
	\]
	Then $\rmk{v_\beta}(x)>0$ for every $x\in\mathbb T^2\setminus\{0\}$, and there exists a constant $\rmk{v_{\beta,*}}>0$ such that
	\[
	\rmk{v_\beta}(x)\ge \rmk{v_{\beta,*}}
	\qquad\text{for all }x\in\mathbb T^2\setminus\{0\}.
	\]

\label{lem:sum}
	(i) (\cite[Lemma 3.10]{ZZ15}) Let $0<l,m<d$ and $l+m-d>0$. Then
	\begin{equation}\label{eq:sum-general}
		\sum_{k_1\in \mathbb{Z}^d}\frac{1}{\langle k_1\rangle^{l}\langle k-k_1\rangle^{m}}
		\lesssim \frac{1}{\langle k\rangle ^{l+m-d}}.
	\end{equation}

	(ii) In dimension $d=2$,
	\begin{equation}\label{eq:sum-log}
		\sum_{p\in\mathbb Z^2}\frac1{(|p+k|^2+1)(|p|^2+1)}
		\lesssim \frac{\log(2+|k|)}{1+|k|^2}.
	\end{equation}

[Shifted fractional-Bessel $k$-sums]\label{lem:shifted-Yukawa-sums}
	Let $\frac32<\beta\le2$, $0<s<1$, and $0<s_1\le s_2<1$. Then
	\begin{align}
		\sum_{k\neq 0} |#1{\widehat v_\beta}(k)|^2 \langle k+\ell\rangle^{-2s}
		&\le C_{\beta,s}\,\langle \ell\rangle^{-2s}, \label{eq:shifted-v-sum-1}\\
		\sum_{k\neq 0} |#1{\widehat v_\beta}(k)|^2
		\langle k+\ell\rangle^{-2s_1}\langle \ell-k\rangle^{-2s_2}
		&\le C_{\beta,s_1,s_2}\,\langle \ell\rangle^{-2s_1}. \label{eq:shifted-v-sum-2}
	\end{align}

